const e=require("fs"),r=e.readdirSync(".").filter(e=>e.endsWith(".html"));for(const t of r){let r=e.readFileSync(t,"utf8");r=r.replace(/<link rel="dns-prefetch" href="https:\/\/res\.cloudinary\.com">/g,'<link rel="preconnect" href="https://res.cloudinary.com">'),r=r.replace(/<link rel="dns-prefetch" href="https:\/\/firestore\.googleapis\.com">/g,'<link rel="preconnect" href="https://firestore.googleapis.com">'),r=r.replace(/<link rel="dns-prefetch" href="https:\/\/identitytoolkit\.googleapis\.com">/g,'<link rel="preconnect" href="https://identitytoolkit.googleapis.com">'),e.writeFileSync(t,r)}console.log("Done reverting preconnects");